import{_ as e,c as t,o as r,aj as o}from"./chunks/framework.CjkNaYQl.js";const p=JSON.parse('{"title":"3. 更多比賽細節","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/3.md","filePath":"advanced/3.md"}'),n={name:"advanced/3.md"};function d(i,a,l,s,c,_){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="_3-更多比賽細節" tabindex="-1">3. 更多比賽細節 <a class="header-anchor" href="#_3-更多比賽細節" aria-label="Permalink to &quot;3. 更多比賽細節&quot;">​</a></h1><h2 id="住宿經驗" tabindex="-1">住宿經驗 <a class="header-anchor" href="#住宿經驗" aria-label="Permalink to &quot;住宿經驗&quot;">​</a></h2><p>住宿地點其實就是台中高工的宿舍，房間是下書桌上床的那種上下舖，因為能進營隊的隊伍不多，所以大概都是一隊一間房。房間內的設備還算不錯，有插頭、書桌、帶洗手槽的陽台，空間也算蠻寬敞的。睡眠品質的部分其實不太理想，因為賽前只會要求你要帶睡袋，但睡袋睡在床板上的感覺，和直接睡在床板上其實也沒什麼差別，整個硬到不行，可以的話，建議可以多帶幾條被子來墊。</p><h2 id="練習和休息時間" tabindex="-1">練習和休息時間 <a class="header-anchor" href="#練習和休息時間" aria-label="Permalink to &quot;練習和休息時間&quot;">​</a></h2><p>每天的課程結束到吃飯前，以及飯後到回宿舍前，都是可以自由練習的時間，在這段時間中，你可以和你的隊友一起練習今天上到的內容，練到真的很熟之後，還可以自己加入許多額外的創意，讓你想學的東西和學過的東西相結合，會能更快學到如何運用不同功能來寫專案。</p><p>至於休息，其實在回宿舍前的一段時間，營隊的人會帶隊去附近的全聯購物，你可以在那段時間裡，買一堆吃的喝的，帶回宿舍晚上吃。</p><h2 id="軟體更新" tabindex="-1">軟體更新 <a class="header-anchor" href="#軟體更新" aria-label="Permalink to &quot;軟體更新&quot;">​</a></h2><p>達明的軟體之前其實蠻常更新的，而更新是有可能刪除和新增功能，甚至改 UI，所以這點要特別注意，要是營隊遇到了新版本，就得好好熟悉一下它了，到了決賽才能擁有比較高的熟悉度。</p>',8)])])}const m=e(n,[["render",d]]);export{p as __pageData,m as default};
